namespace BlazorNotifications.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<Notification> _notifications = new();
    private readonly Lock _lock = new();

    public NotificationService()
    {
        // Seed with initial fake data
        _notifications.Add(new Notification(_nextId++, "Welcome to the notification system!", DateTime.UtcNow.AddMinutes(-10)));
        _notifications.Add(new Notification(_nextId++, "Your profile was updated successfully.", DateTime.UtcNow.AddMinutes(-5)));
        _notifications.Add(new Notification(_nextId++, "New feature: dark mode is now available.", DateTime.UtcNow.AddMinutes(-2)));
    }

    /// <summary>
    /// Returns all notifications currently available.
    /// </summary>
    public List<Notification> GetNotifications()
    {
        lock (_lock)
        {
            return _notifications.ToList();
        }
    }

    /// <summary>
    /// Returns only notifications newer than the given ID.
    /// </summary>
    public List<Notification> GetNotificationsSince(int lastSeenId)
    {
        lock (_lock)
        {
            return _notifications.Where(n => n.Id > lastSeenId).ToList();
        }
    }

    /// <summary>
    /// Simulates new notifications arriving over time.
    /// Called internally to generate fake data.
    /// </summary>
    public void SimulateNewNotification()
    {
        var messages = new[]
        {
            "You have a new follower!",
            "Someone commented on your post.",
            "Your build completed successfully.",
            "Reminder: team standup in 15 minutes.",
            "New deployment detected in production.",
            "Security alert: password changed.",
            "You were mentioned in a discussion.",
        };

        lock (_lock)
        {
            var message = messages[_nextId % messages.Length];
            _notifications.Add(new Notification(_nextId++, message, DateTime.UtcNow));
        }
    }
}

